        }
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public TaskItem Task { get; set; } = default!;

    [Parameter]
    public bool ShowMoveLeft { get; set; }

    [Parameter]
    public bool ShowMoveRight { get; set; }

    [Parameter]
    public EventCallback OnMoveLeft { get; set; }

    [Parameter]
    public EventCallback OnMoveRight { get; set; }

    [Parameter]
    public bool IsMoving { get; set; }
}
"}

{"path": "/tmp/sv-ede8dda1667f4d60a4ed66c34cf9189f/Components/Pages/Board/AddTaskForm.razor", "file_text": "<div class="add-task-form">
    <div class="form-group">
        <label>Title</label>
        <input type="text" @bind="title" placeholder="Task title" />
    </div>
    <div class="form-group">
        <label>Assignee</label>
        <input type="text" @bind="assignee" placeholder="Assignee name" />
    </div>
    <div class="form-group">
        <label>Priority</label>
        <select @bind="priority">
            <option value="High">High</option>
            <option value="Medium">Medium</option>
            <option value="Low">Low</option>
        </select>
    </div>
    <div class="form-group">
        <label>Due Date</label>
        <input type="date" @bind="dueDate" />
    </div>
    <div class="form-actions">
        <button class="btn-save" @onclick="HandleSave" disabled="@isSaving">Save</button>
        <button class="btn-cancel" @onclick="OnCancel" disabled="@isSaving">Cancel</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public string DefaultStatus { get; set; } = default!;

    [Parameter]
    public EventCallback<TaskItem> OnTaskCreated { get; set; }

    [Parameter]
    public EventCallback OnCancel { get; set; }

    [Parameter, EditorRequired]
    public ITaskService TaskService { get; set; } = default!;

    private string title = string.Empty;
    private string assignee = string.Empty;
    private string priority = "Medium";
    private DateTime dueDate = DateTime.Today.AddDays(7);
    private bool isSaving;

    private async Task HandleSave()
    {
        if (string.IsNullOrWhiteSpace(title))
            return;

        isSaving = true;
        try
        {
            var newTask = await TaskService.CreateTaskAsync(title, assignee, priority, dueDate);
            await OnTaskCreated.InvokeAsync(newTask);
        }
        finally
        {
            isSaving = false;
        }
    }
}
"}

