{"path": "/tmp/sv-ede8dda1667f4d60a4ed66c34cf9189f/Components/Pages/Board/BoardSearchBar.razor", "file_text": "<div class="board-search-bar">
    <input type="text"
           placeholder="Search tasks by title..."
           value="@SearchTerm"
           @oninput="HandleInput" />
</div>

@code {
    [Parameter]
    public string SearchTerm { get; set; } = string.Empty;

    [Parameter]
    public EventCallback<string> OnSearchChanged { get; set; }

    private async Task HandleInput(ChangeEventArgs e)
    {
        await OnSearchChanged.InvokeAsync(e.Value?.ToString() ?? string.Empty);
    }
}
"}

{"path": "/tmp/sv-ede8dda1667f4d60a4ed66c34cf9189f/Components/Pages/Board/BoardColumn.razor", "file_text": "<div class="board-column">
    <div class="column-header">
        <h3>@ColumnName</h3>
        <span class="column-count">@Tasks.Count</span>
    </div>

    <div class="column-tasks">
        @foreach (var task in Tasks)
        {
            <TaskCard Task="task"
                      ShowMoveLeft="ShowMoveLeft"
                      ShowMoveRight="ShowMoveRight"
                      IsMoving="movingTaskId == task.Id"
                      OnMoveLeft="() => HandleMoveLeft(task)"
                      OnMoveRight="() => HandleMoveRight(task)" />
        }
    </div>

    @if (showAddForm)
    {
        <AddTaskForm DefaultStatus="@ColumnName"
                     TaskService="TaskService"
                     OnTaskCreated="HandleTaskCreated"
                     OnCancel="() => showAddForm = false" />
    }
    else
    {
        <button class="btn-add-task" @onclick="() => showAddForm = true">+ Add Task</button>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public string ColumnName { get; set; } = default!;

    [Parameter]
    public List<TaskItem> Tasks { get; set; } = new();

    [Parameter]
    public bool ShowMoveLeft { get; set; }

    [Parameter]
    public bool ShowMoveRight { get; set; }

    [Parameter]
    public EventCallback<(TaskItem Task, string Direction)> OnMoveTask { get; set; }

    [Parameter]
    public EventCallback<TaskItem> OnTaskCreated { get; set; }

    [Parameter, EditorRequired]
    public ITaskService TaskService { get; set; } = default!;

    private bool showAddForm;
    private int? movingTaskId;

    private async Task HandleMoveLeft(TaskItem task)
    {
        movingTaskId = task.Id;
        try
        {
            await OnMoveTask.InvokeAsync((task, "left"));
        }
        finally
        {
            movingTaskId = null;
        }
    }

    private async Task HandleMoveRight(TaskItem task)
    {
        movingTaskId = task.Id;
        try
        {
            await OnMoveTask.InvokeAsync((task, "right"));
        }
        finally
        {
            movingTaskId = null;
        }
    }

    private async Task HandleTaskCreated(TaskItem newTask)
    {
        showAddForm = false;
        await OnTaskCreated.InvokeAsync(newTask);
    }
}
"}

