@page "/board"
@using sv_ede8dda1667f4d60a4ed66c34cf9189f.Components.Pages.Board
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h2>Project Board</h2>

@if (isLoading)
{
    <p class="board-loading">Loading tasks...</p>
}
else if (errorMessage is not null)
{
    <div class="board-error">
        <p>@errorMessage</p>
        <button @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardSummaryBar TotalCount="allTasks.Count"
                     TodoCount="GetTasksForStatus("To Do").Count"
                     InProgressCount="GetTasksForStatus("In Progress").Count"
                     DoneCount="GetTasksForStatus("Done").Count"
                     OverdueCount="allTasks.Count(t => t.DueDate < DateTime.Today)" />

    <BoardSearchBar SearchTerm="@searchTerm" OnSearchChanged="HandleSearchChanged" />

    <div class="board-columns">
        @for (int i = 0; i < columns.Length; i++)
        {
            var colIndex = i;
            <BoardColumn ColumnName="@columns[colIndex]"
                         Tasks="GetFilteredTasksForStatus(columns[colIndex])"
                         ShowMoveLeft="colIndex > 0"
                         ShowMoveRight="colIndex < columns.Length - 1"
                         TaskService="TaskService"
                         OnMoveTask="args => HandleMoveTask(args.Task, args.Direction)"
                         OnTaskCreated="HandleTaskCreated" />
        }
    </div>
}

@code {
    private static readonly string[] columns = ["To Do", "In Progress", "Done"];

    private List<TaskItem> allTasks = new();
    private string searchTerm = string.Empty;
    private bool isLoading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        isLoading = true;
        errorMessage = null;
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private List<TaskItem> GetTasksForStatus(string status) =>
        allTasks.Where(t => t.Status == status).ToList();

    private List<TaskItem> GetFilteredTasksForStatus(string status) =>
        allTasks
            .Where(t => t.Status == status)
            .Where(t => string.IsNullOrWhiteSpace(searchTerm) ||
                        t.Title.Contains(searchTerm, StringComparison.OrdinalIgnoreCase))
            .ToList();

    private void HandleSearchChanged(string term)
    {
        searchTerm = term;
    }

    private async Task HandleMoveTask(TaskItem task, string direction)
    {
        var currentIndex = Array.IndexOf(columns, task.Status);
        var newIndex = direction == "left" ? currentIndex - 1 : currentIndex + 1;

        if (newIndex < 0 || newIndex >= columns.Length)
            return;

        var newStatus = columns[newIndex];
        await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);

        var index = allTasks.FindIndex(t => t.Id == task.Id);
        if (index >= 0)
        {
            allTasks[index] = task with { Status = newStatus };
        }
    }

    private void HandleTaskCreated(TaskItem newTask)
    {
        allTasks.Add(newTask);
    }
}

h2 {
    margin-bottom: 1rem;
}

.board-loading,
.board-error {
    padding: 2rem;
    text-align: center;
}

.board-error {
    color: #dc3545;
}

.board-error button {
    margin-top: 0.5rem;
    padding: 0.4rem 1rem;
    cursor: pointer;
}

/* Summary Bar */
.board-summary-bar {
    display: flex;
    gap: 1.5rem;
    padding: 1rem;
    background: #f8f9fa;
    border-radius: 6px;
    margin-bottom: 1rem;
    flex-wrap: wrap;
}

.summary-stat {
    display: flex;
    flex-direction: column;
    align-items: center;
}

.stat-label {
    font-size: 0.8rem;
    color: #6c757d;
    text-transform: uppercase;
}

.stat-value {
    font-size: 1.4rem;
    font-weight: 700;
}

.summary-overdue .stat-value {
    color: #dc3545;
}

/* Search Bar */
.board-search-bar {
    margin-bottom: 1rem;
}

.board-search-bar input {
    width: 100%;
    padding: 0.5rem 0.75rem;
    border: 1px solid #dee2e6;
    border-radius: 4px;
    font-size: 0.95rem;
    box-sizing: border-box;
}

/* Columns */
.board-columns {
    display: flex;
    gap: 1rem;
    align-items: flex-start;
}

.board-column {
    flex: 1;
    background: #f1f3f5;
    border-radius: 6px;
    padding: 0.75rem;
    min-width: 0;
}

.column-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 0.75rem;
}

.column-header h3 {
    margin: 0;
    font-size: 1rem;
}

.column-count {
    background: #dee2e6;
    border-radius: 999px;
    padding: 0.15rem 0.55rem;
    font-size: 0.8rem;
    font-weight: 600;
}

/* Task Card */
.task-card {
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 6px;
    padding: 0.75rem;
    margin-bottom: 0.5rem;
}

.task-title {
    margin: 0 0 0.25rem;
    font-size: 0.95rem;
}

.task-assignee {
    margin: 0 0 0.4rem;
    font-size: 0.8rem;
    color: #6c757d;
}

.priority-badge {
    display: inline-block;
    padding: 0.15rem 0.5rem;
    border-radius: 4px;
    font-size: 0.75rem;
    font-weight: 600;
    margin-right: 0.5rem;
}

.priority-high {
    background: #dc3545;
    color: #fff;
}

.priority-medium {
    background: #ffc107;
    color: #212529;
}

.priority-low {
    background: #28a745;
    color: #fff;
}

.task-due-date {
    font-size: 0.8rem;
    color: #495057;
}

.task-actions {
    margin-top: 0.5rem;
    display: flex;
    gap: 0.4rem;
}

.btn-move {
    padding: 0.2rem 0.5rem;
    font-size: 0.75rem;
    border: 1px solid #ced4da;
    background: #fff;
    border-radius: 4px;
    cursor: pointer;
}

.btn-move:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

.btn-move:hover:not(:disabled) {
    background: #e9ecef;
}

/* Add Task */
.btn-add-task {
    width: 100%;
    padding: 0.5rem;
    background: transparent;
    border: 2px dashed #ced4da;
    border-radius: 6px;
    color: #6c757d;
    cursor: pointer;
    font-size: 0.85rem;
}

.btn-add-task:hover {
    border-color: #868e96;
    color: #495057;
}

.add-task-form {
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 6px;
    padding: 0.75rem;
}

.form-group {
    margin-bottom: 0.5rem;
}

.form-group label {
    display: block;
    font-size: 0.8rem;
    font-weight: 600;
    margin-bottom: 0.15rem;
}

.form-group input,
.form-group select {
    width: 100%;
    padding: 0.35rem 0.5rem;
    border: 1px solid #ced4da;
    border-radius: 4px;
    font-size: 0.85rem;
    box-sizing: border-box;
}

.form-actions {
    display: flex;
    gap: 0.4rem;
    margin-top: 0.5rem;
}

.btn-save {
    padding: 0.35rem 0.75rem;
    background: #0d6efd;
    color: #fff;
    border: none;
    border-radius: 4px;
    cursor: pointer;
    font-size: 0.85rem;
}

.btn-save:disabled {
    opacity: 0.6;
    cursor: not-allowed;
}

.btn-cancel {
    padding: 0.35rem 0.75rem;
    background: #fff;
    border: 1px solid #ced4da;
    border-radius: 4px;
    cursor: pointer;
    font-size: 0.85rem;
}

.btn-cancel:disabled {
    opacity: 0.6;
    cursor: not-allowed;
}

